                    <button key={value} aria-label={`Open bento metric ${["Number of deploys", "Average deploy time", "Number of servers"][index]}`} aria-pressed={activeNavItem === value} className={cn("rounded-2xl bg-slate-900/70 p-5 text-left transition duration-200 hover:-translate-y-0.5 hover:bg-slate-900 focus:outline-none focus:ring-2 focus:ring-indigo-400/40 active:scale-[0.99]", activeNavItem === value && "ring-1 ring-indigo-300/60")} type="button" onClick={() => selectBentoAction(value, `${["Deploy count", "Deploy time", "Server count"][index]} opened`)}>
                      <p className="text-sm text-slate-400">{["Number of deploys", "Avg deploy time", "Number of servers"][index]}</p>
                      <p className="mt-3 text-4xl font-semibold">{value}</p>
                    </button>
