        <span className={cn("grid size-6 shrink-0 place-items-center rounded-sm text-[10px] font-black", isDarkLogo ? "bg-white/10 text-white ring-1 ring-white/15" : "bg-slate-900 text-white")}>{logo.mark}</span>
