                <button aria-label="Open logo contact request" aria-pressed={activeNavItem === "Contact request"} className={cn("font-semibold transition hover:-translate-y-0.5 focus:outline-none focus:ring-2 focus:ring-indigo-400/50 active:scale-[0.98]", isDarkLogo ? "text-slate-300 hover:text-white" : "text-slate-700 hover:text-slate-950")} type="button" onClick={() => openLogoAction("Contact request", "Contact request opened")}>Contact us</button>
