        {navMenuOpen && <div className={cn("mx-auto mt-3 grid max-w-6xl gap-2 rounded-lg p-3 text-sm shadow-sm transition duration-200 animate-in fade-in slide-in-from-top-2 md:hidden", headerSurfaceDark ? "bg-white/10 text-white" : "bg-slate-50 text-slate-700")}>{navItems.map((item) => <button key={item} aria-label={`Open header mobile ${item}`} aria-pressed={activeNavItem === `mobile-${item}`} className="rounded-md px-3 py-2 text-left transition hover:bg-white/10 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-indigo-400/60" type="button" onClick={() => openHeaderAction(`mobile-${item}`, `${item} mobile header opened`)}>{item}</button>)}</div>}
