          <path d="M3 21.1c3.2-6.2 8.8-7.6 14.1-3.9 4.2 3 7 2.4 10.5-2.1l5.4 3.8c-5.7 7.4-12.4 8.5-19.4 3.3-2.3-1.7-3.7-1.2-5.3 2.1L3 21.1Z" />
