        <button className="rounded-md bg-indigo-600 px-3.5 py-2 text-sm font-semibold text-white shadow-sm transition hover:bg-indigo-500 active:scale-[0.98]" type="button" onClick={() => setPostedComment("Form layout saved")}>Save</button>
