      fading: "/assets/ecommerce-promo-sections/fading-bedroom.png",
      full: "/assets/ecommerce-promo-sections/full-background-outdoor.png",
      fullOverlap: "/assets/ecommerce-promo-sections/full-overlap-kitchen.png",
      compact: "/assets/ecommerce-promo-sections/background-skincare.png",
      overlap: "/assets/ecommerce-promo-sections/overlap-apparel.png",
      split: "/assets/ecommerce-promo-sections/offers-split-travel.png",
      large: "/assets/ecommerce-promo-sections/large-content-furniture.png",
      support: "/assets/ecommerce-promo-sections/supporting-desk.png",
