    const orderDetailMutedClass = isOrderDetailPageDark ? "text-slate-300" : "text-slate-500"
    const orderDetailHeadingClass = isOrderDetailPageDark ? "text-slate-100" : "text-slate-950"
    const orderDetailBorderClass = isOrderDetailPageDark ? "border-slate-800" : "border-slate-200"
